-- LEZ-17 (B1) — Nieuwe parkeerregels
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000017', 'B1', 'lezen', 'Nieuwe parkeerregels',
  'Je leest een bericht op de website van de gemeente.', 117, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000017', 'reading_text', 'Lees de tekst.', '{"text":"Vanaf 1 januari wordt in de wijk Noord betaald parkeren ingevoerd. Volgens de gemeente staan veel parkeerplaatsen overdag vol met auto''s van mensen die buiten de wijk werken. Bewoners vinden daardoor vaak geen plek dicht bij huis. Met vergunningen voor bewoners en een hoger tarief voor langparkeerders wil de gemeente de parkeerdruk verminderen. Tegelijkertijd worden twee extra fietsenstallingen en een betere busverbinding aangelegd."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000017', 'open_text', 'Beantwoord de vraag.', '{"question":"Wat is de belangrijkste reden voor de nieuwe parkeerregels?"}'::jsonb, '{"answer":"De gemeente wil de parkeerdruk verminderen, zodat bewoners makkelijker een plek kunnen vinden.","explanation":"De tekst noemt meerdere maatregelen, maar het centrale probleem is dat bewoners door langparkeerders moeilijk een plek vinden."}'::jsonb, 2
);

-- LEZ-18 (B1) — Thuiswerkbeleid
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
