insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000018', 'reading_text', 'Lees de tekst.', '{"text":"Medewerkers mogen na overleg met hun leidinggevende maximaal twee dagen per week thuiswerken. Dinsdag is de vaste teamdag; iedereen werkt dan op kantoor. Alleen bij ziekte, mantelzorg of een andere bijzondere situatie kan de manager een uitzondering toestaan. De afspraken worden iedere drie maanden geëvalueerd."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000018', 'open_text', 'Beantwoord de vraag.', '{"question":"Mag een medewerker zonder bijzondere reden op dinsdag thuiswerken?"}'::jsonb, '{"answer":"Nee. Dinsdag is de verplichte teamdag op kantoor.","explanation":"Alleen in een bijzondere situatie kan de manager een uitzondering geven."}'::jsonb, 2
);

