insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000022', 'reading_text', 'Lees de tekst.', '{"text":"Dank voor uw melding over de kapotte lantaarnpaal. Normale storingen proberen wij binnen tien werkdagen te herstellen. Ziet u losse elektriciteitsdraden, rook of een andere direct gevaarlijke situatie? Bel dan onmiddellijk het storingsnummer en blijf op afstand."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000022', 'open_text', 'Beantwoord de vraag.', '{"question":"Wat moet je doen als er losse elektriciteitsdraden zichtbaar zijn?"}'::jsonb, '{"answer":"Onmiddellijk het storingsnummer bellen en op afstand blijven.","explanation":"Losse draden vallen onder een direct gevaarlijke situatie; daarvoor geldt niet de gewone wachttijd."}'::jsonb, 2
);

-- LEZ-23 (B1) — Vrijwilliger voor een taalcafé
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000023', 'B1', 'lezen', 'Vrijwilliger voor een taalcafé',
  'Je leest een vrijwilligersvacature.', 123, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000023', 'reading_text', 'Lees de tekst.', '{"text":"Voor ons wekelijkse taalcafé zoeken wij een gespreksbegeleider. Je helpt een kleine groep nieuwkomers oefenen met alledaagse gesprekken. Ervaring als docent is niet verplicht, maar je spreekt minimaal Nederlands op B1-niveau en bent op woensdagavond twee uur beschikbaar. Voor de start krijg je een korte training en begeleiding van een coördinator."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000023', 'open_text', 'Beantwoord de vraag.', '{"question":"Noem twee eisen waaraan een vrijwilliger moet voldoen."}'::jsonb, '{"answer":"Minimaal Nederlands op B1-niveau spreken en op woensdagavond twee uur beschikbaar zijn.","explanation":"Docentervaring is juist niet verplicht. De taalvaardigheid en beschikbaarheid zijn wel eisen."}'::jsonb, 2
);

-- LEZ-24 (B2) — Proef met een vierdaagse werkweek
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000024', 'B2', 'lezen', 'Proef met een vierdaagse werkweek',
  'Je leest een opiniestuk in een vakblad.', 124, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000024', 'reading_text', 'Lees de tekst.', '{"text":"Voorstanders van een vierdaagse werkweek wijzen op minder stress en een hogere productiviteit. Tegenstanders vrezen dat de werkdruk op de overblijvende dagen juist toeneemt en dat niet iedere sector hetzelfde werk in minder tijd kan uitvoeren. Beide bezwaren zijn serieus. Toch is niets doen evenmin verstandig, nu uitval door overbelasting groeit. Organisaties zouden daarom niet meteen een algemene vierdaagse week moeten invoeren, maar wel tijdelijke pilots moeten starten. Alleen door per functie gegevens over werkdruk, kwaliteit en klanttevredenheid te verzamelen, kan worden bepaald waar het model werkelijk werkt."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000024', 'open_text', 'Beantwoord de vraag.', '{"question":"Welk standpunt neemt de schrijver in?"}'::jsonb, '{"answer":"De schrijver pleit voor tijdelijke, zorgvuldig gemeten pilots en niet voor onmiddellijke algemene invoering.","explanation":"De schrijver erkent argumenten van beide kanten en kiest voor gecontroleerd experimenteren."}'::jsonb, 2
);

-- LEZ-25 (B2) — Inspraak bij een wijkplan
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000025', 'B2', 'lezen', 'Inspraak bij een wijkplan',
  'Je leest een samenvatting van een gemeentelijk beleidsdocument.', 125, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000025', 'reading_text', 'Lees de tekst.', '{"text":"De gemeente wil bewoners eerder betrekken bij de herinrichting van de wijk. Digitale enquêtes leveren snel veel reacties op, maar bereiken vooral hoger opgeleide inwoners die al betrokken zijn. Fysieke bijeenkomsten bieden meer ruimte voor gesprek, terwijl mensen met onregelmatige werktijden of zorgtaken daar juist moeilijk aanwezig kunnen zijn. Het beleidsvoorstel combineert daarom online reacties, straatinterviews en gesprekken via bestaande buurtorganisaties. De vraag blijft echter hoe de gemeente kan voorkomen dat een kleine, zeer actieve groep onevenredig veel invloed krijgt."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000025', 'open_text', 'Beantwoord de vraag.', '{"question":"Wat is het centrale dilemma in deze tekst?"}'::jsonb, '{"answer":"Hoe de gemeente brede en representatieve inspraak kan organiseren zonder dat vooral een kleine actieve groep de uitkomst bepaalt.","explanation":"De methoden hebben elk sterke en zwakke kanten; representativiteit is het onopgeloste kernprobleem."}'::jsonb, 2
);

-- LEZ-26 (B2) — Voorwaarden van een fictieve zorgpolis
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000026', 'B2', 'lezen', 'Voorwaarden van een fictieve zorgpolis',
  'Je vergelijkt voorwaarden. De polis in deze opdracht is fictief.', 126, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000026', 'reading_text', 'Lees de tekst.', '{"text":"Bij Polis Helder vallen de meeste ziekenhuisbehandelingen onder het verplichte eigen risico. Een regulier bezoek aan de huisarts wordt daarentegen rechtstreeks uit de basisdekking betaald. Laboratoriumonderzoek dat de huisarts aanvraagt, kan volgens de polis wél ten laste van het eigen risico komen. Voor niet-spoedeisende zorg bij een aanbieder zonder contract vergoedt de verzekeraar maximaal 70 procent van het gebruikelijke tarief."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000026', 'open_text', 'Beantwoord de vraag.', '{"question":"Welke kosten vallen volgens deze fictieve tekst niet onder het verplichte eigen risico?"}'::jsonb, '{"answer":"Het reguliere bezoek aan de huisarts.","explanation":"De tekst maakt expliciet onderscheid tussen het huisartsbezoek en eventueel laboratoriumonderzoek."}'::jsonb, 2
);

-- LEZ-27 (B2) — Besluit over zonnepanelen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000027', 'B2', 'lezen', 'Besluit over zonnepanelen',
  'Je leest notulen van een fictieve vereniging van eigenaars.', 127, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000027', 'reading_text', 'Lees de tekst.', '{"text":"De ledenvergadering staat in principe positief tegenover zonnepanelen op het gezamenlijke dak. Het bestuur mag offertes opvragen, maar een definitief contract wordt pas gesloten wanneer aan twee voorwaarden is voldaan: ten minste twee derde van de uitgebrachte stemmen is vóór en de beschikbare subsidie dekt minimaal twintig procent van de investering. Als de subsidie lager uitvalt, wordt het voorstel opnieuw aan de leden voorgelegd, ook wanneer er al voldoende stemmen zijn."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000027', 'open_text', 'Beantwoord de vraag.', '{"question":"Onder welke twee voorwaarden kan het bestuur direct een definitief contract sluiten?"}'::jsonb, '{"answer":"Minstens twee derde van de stemmen moet vóór zijn én de subsidie moet minimaal twintig procent van de investering dekken.","explanation":"Beide voorwaarden zijn noodzakelijk; één voorwaarde alleen is niet genoeg."}'::jsonb, 2
);

-- LEZ-28 (B2) — Gespreid leren
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000028', 'B2', 'lezen', 'Gespreid leren',
  'Je leest een korte tekst over taalverwerving.', 128, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000028', 'reading_text', 'Lees de tekst.', '{"text":"Veel cursisten besteden vlak voor een toets enkele lange avonden aan woordenschat. Daarmee kunnen zij op korte termijn redelijk scoren, maar een groot deel van de kennis verdwijnt daarna snel. Wanneer dezelfde leertijd over meerdere weken wordt verdeeld en woorden telkens in een andere context terugkomen, kost het ophalen aanvankelijk meer moeite. Juist die inspanning versterkt echter het geheugen. Effectief leren voelt dus niet altijd gemakkelijk: een methode die tijdens het oefenen trager lijkt, kan op langere termijn duurzamere resultaten opleveren."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000028', 'open_text', 'Beantwoord de vraag.', '{"question":"Welke conclusie ondersteunt de tekst het best?"}'::jsonb, '{"answer":"Gespreid en herhaald oefenen levert op lange termijn duurzamere kennis op dan alles kort voor een toets leren.","explanation":"De tekst contrasteert een snel kortetermijneffect met sterker langetermijnbehoud."}'::jsonb, 2
);

-- LEZ-29 (B2) — Belangenverstrengeling op het werk
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000029', 'B2', 'lezen', 'Belangenverstrengeling op het werk',
  'Je leest een fragment uit een fictieve gedragscode.', 129, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000029', 'reading_text', 'Lees de tekst.', '{"text":"Medewerkers vermijden situaties waarin persoonlijke belangen hun professionele oordeel kunnen beïnvloeden, of de indruk daarvan kunnen wekken. Een mogelijk belangenconflict moet direct aan de leidinggevende worden gemeld, ook wanneer de medewerker ervan overtuigd is objectief te kunnen handelen. Voorbeelden zijn een financieel belang in een leverancier, betaalde nevenwerkzaamheden voor een concurrent of een nauwe persoonlijke relatie met iemand die meedingt naar een opdracht."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000029', 'open_text', 'Beantwoord de vraag.', '{"question":"Een medewerker beoordeelt offertes en haar broer werkt bij één van de leveranciers. Wat moet zij volgens de code doen?"}'::jsonb, '{"answer":"De nauwe persoonlijke relatie direct aan haar leidinggevende melden als mogelijk belangenconflict.","explanation":"Niet alleen echte beïnvloeding, maar ook de mogelijke indruk daarvan moet worden gemeld."}'::jsonb, 2
);

-- LEZ-30 (B2) — Tijdelijk verkeersplan
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000030', 'B2', 'lezen', 'Tijdelijk verkeersplan',
  'Je leest een samenvatting van een bewonersconsultatie.', 130, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000030', 'reading_text', 'Lees de tekst.', '{"text":"De meeste bewoners steunen de aanleg van een veiligere fietsroute, mits de bereikbaarheid van winkels behouden blijft. Ondernemers vrezen omzetverlies tijdens de werkzaamheden en vragen om duidelijke omleidingsborden. De gemeente heeft toegezegd de bevoorrading vóór 10.00 uur mogelijk te maken en extra tijdelijke parkeerplaatsen aan te leggen. Voor bewoners met een mobiliteitsbeperking is echter nog niet uitgewerkt hoe zij tijdens iedere bouwfase hun woning of de bushalte kunnen bereiken."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000030', 'open_text', 'Beantwoord de vraag.', '{"question":"Welk belangrijk probleem is aan het einde van de tekst nog niet opgelost?"}'::jsonb, '{"answer":"De bereikbaarheid voor bewoners met een mobiliteitsbeperking tijdens de werkzaamheden.","explanation":"Voor bevoorrading en parkeren zijn maatregelen genoemd; voor deze groep ontbreekt nog een uitgewerkt plan."}'::jsonb, 2
);

