insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000040', 'listening_clip', 'De tandarts geeft advies na een behandeling.', '{"script":"De vulling is klaar. Uw mond is nog verdoofd. Eet daarom pas wanneer de verdoving helemaal weg is; meestal duurt dat ongeveer twee uur. Water drinken mag wel meteen. Bel ons als u later veel pijn krijgt."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000040', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wanneer mag de patiënt weer eten?","options":["Meteen na de behandeling","Na ongeveer een halfuur","Als de verdoving weg is, ongeveer na twee uur","Pas de volgende ochtend"]}'::jsonb, '{"correctIndex":2,"explanation":"Het drinken mag meteen, maar voor eten geldt een andere instructie."}'::jsonb, 2
);

