insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000044', 'listening_clip', 'Je buurvrouw legt uit waarom er geluid is.', '{"script":"Hoi, ik wil even zeggen dat we zondag een kast aan de muur bevestigen. We moeten daarvoor boren. We beginnen rond elf uur en proberen uiterlijk om één uur klaar te zijn. Daarna doen we alleen nog stil werk."}'::jsonb, null, 1
