insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000045', 'listening_clip', 'De kinderopvang geeft een instructie.', '{"script":"De opvang sluit om half zeven. Kunt u zelf niet komen en haalt uw broer uw dochter op? Geef zijn naam dan vooraf aan ons door. Omdat wij hem nog niet kennen, moet hij bij de eerste keer een identiteitsbewijs laten zien."}'::jsonb, null, 1
