insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000046', 'listening_clip', 'Een medewerker van de gemeente spreekt een voicemail in.', '{"script":"Goedemiddag, met de gemeente. Wij hebben uw aanvraag ontvangen, maar de originele geboorteakte ontbreekt nog. Een kopie is voor deze aanvraag niet voldoende. Wilt u het originele document vóór twintig augustus bij de balie laten zien?"}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
