);

-- LUI-17 (B1) — Vrijwilligers tegen eenzaamheid
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000047', 'B1', 'luisteren', 'Vrijwilligers tegen eenzaamheid',
  'Je hoort een kort radio-interview met een vrijwilligersorganisatie.', 117, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000047', 'listening_clip', 'Je hoort een kort radio-interview met een vrijwilligersorganisatie.', '{"script":"Presentator: Waarom zoekt uw organisatie nieuwe vrijwilligers?\nCoördinator: Veel ouderen wonen zelfstandig en redden zich praktisch best goed, maar spreken soms dagenlang niemand. Onze vrijwilligers bellen iedere week op een vast moment of gaan af en toe langs voor een kop koffie. Het gaat niet om huishoudelijke hulp of zorg. Het belangrijkste is dat iemand oprechte aandacht krijgt en weer een regelmatig sociaal contact heeft. Vrijwilligers krijgen vooraf een korte training."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000047', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat is het belangrijkste doel van het vrijwilligersproject?","options":["Ouderen leren omgaan met computers","Ouderen helpen met hun administratie","Het sociale contact van eenzame ouderen vergroten","Geld inzamelen voor een woonzorgcentrum"]}'::jsonb, '{"correctIndex":2,"explanation":"De coördinator zegt expliciet dat het niet om zorg of huishoudelijke hulp gaat."}'::jsonb, 2
);

-- LUI-18 (B1) — Veiligheid in het magazijn
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000048', 'B1', 'luisteren', 'Veiligheid in het magazijn',
  'Je hoort een veiligheidsinstructie op het werk.', 118, false
