insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000048', 'listening_clip', 'Je hoort een veiligheidsinstructie op het werk.', '{"script":"Draag in het magazijn altijd uw veiligheidsschoenen en fluorescerende vest. Telefoons blijven in de locker, behalve wanneer een leidinggevende toestemming geeft. Ziet u olie, water of een andere vloeistof op de vloer, zet de plek dan onmiddellijk af en meld het bij de teamleider. Probeer een grote lekkage niet alleen op te ruimen, omdat heftrucks de gladde plek mogelijk niet op tijd zien."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000048', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat moet een medewerker direct doen wanneer er vloeistof op de vloer ligt?","options":["Zelf doorwerken en het later schoonmaken","De plek afzetten en de teamleider waarschuwen","Alleen een collega mondeling waarschuwen","De ruimte zonder uitleg verlaten"]}'::jsonb, '{"correctIndex":1,"explanation":"Er worden twee directe acties achter elkaar genoemd."}'::jsonb, 2
);

-- LUI-19 (B1) — Advies bij rugpijn
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000049', 'B1', 'luisteren', 'Advies bij rugpijn',
  'Je hoort advies van een doktersassistent.', 119, false
