insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000049', 'listening_clip', 'Je hoort advies van een doktersassistent.', '{"script":"Bij gewone lage rugpijn is het meestal goed om rustig in beweging te blijven. U hoeft dus niet de hele dag in bed te liggen. U kunt eventueel een pijnstiller gebruiken volgens de bijsluiter. Neem wel opnieuw snel contact met ons op als u een doof gevoel in uw been krijgt, minder kracht heeft of problemen krijgt met plassen. Dat zijn signalen die de huisarts wil beoordelen."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000049', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Bij welk symptoom moet de patiënt opnieuw snel contact opnemen?","options":["Lichte spierpijn na wandelen","Vermoeidheid aan het einde van de dag","Een doof gevoel in een been","Minder trek in eten"]}'::jsonb, '{"correctIndex":2,"explanation":"Na `neem wel opnieuw snel contact op als` volgen de waarschuwingssignalen."}'::jsonb, 2
);

-- LUI-20 (B1) — Internetcontract na de einddatum
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000050', 'B1', 'luisteren', 'Internetcontract na de einddatum',
  'Je hoort een gesprek met een internetaanbieder.', 120, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000050', 'listening_clip', 'Je hoort een gesprek met een internetaanbieder.', '{"script":"Klant: Mijn contract loopt volgende maand af. Moet ik iets doen?\nMedewerker: Nee, de verbinding stopt niet. Na de vaste periode loopt het abonnement automatisch per maand door. De tijdelijke korting vervalt dan wel, waardoor u zeven euro meer betaalt. U kunt vanaf dat moment opzeggen met een opzegtermijn van één maand."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000050', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat gebeurt er wanneer de klant niets doet na de vaste contractperiode?","options":["De verbinding stopt meteen","Het contract loopt maandelijks door tegen een hoger tarief","Er start automatisch een nieuw contract van twee jaar","Het maandbedrag wordt lager"]}'::jsonb, '{"correctIndex":1,"explanation":"De verbinding blijft; alleen de korting vervalt en de contractvorm verandert."}'::jsonb, 2
);

-- LUI-21 (B1) — Voorbereiding op een stage
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000051', 'B1', 'luisteren', 'Voorbereiding op een stage',
  'Een stagecoördinator spreekt studenten toe.', 121, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000051', 'listening_clip', 'Een stagecoördinator spreekt studenten toe.', '{"script":"Jullie zoeken in principe zelf een stageplaats en geven die uiterlijk één december aan mij door. Wie moeite heeft met zoeken, kan gebruikmaken van de bedrijvenlijst van school. Let op: je mag pas starten wanneer de stageovereenkomst door jou, het bedrijf en de school is ondertekend. Zonder die handtekeningen ben je tijdens de stage mogelijk niet goed verzekerd."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000051', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat moet geregeld zijn voordat de stage daadwerkelijk begint?","options":["De student moet al een salaris hebben ontvangen","De stageovereenkomst moet door alle partijen zijn ondertekend","De student moet zelf een verzekering afsluiten","De eerste beoordeling moet zijn ingevuld"]}'::jsonb, '{"correctIndex":1,"explanation":"Het woord `pas` introduceert een noodzakelijke voorwaarde."}'::jsonb, 2
);

-- LUI-22 (B1) — Proef met afvalscheiding
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000052', 'B1', 'luisteren', 'Proef met afvalscheiding',
  'Je hoort een lokaal nieuwsbericht.', 122, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000052', 'listening_clip', 'Je hoort een lokaal nieuwsbericht.', '{"script":"In drie wijken loopt sinds januari een proef met aparte bakken voor groente-, fruit- en etensresten. Volgens de gemeente is de hoeveelheid restafval daar met achttien procent afgenomen. Bewoners zijn overwegend positief, maar klaagden tijdens warme weken over geur rond volle bakken. Daarom worden de bakken tussen juni en september een extra keer per week geleegd. Na de zomer beslist de gemeenteraad of de proef wordt uitgebreid."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000052', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waarom gaat de gemeente de afvalbakken in de zomer vaker legen?","options":["Omdat bewoners meer papier weggooien","Omdat de proef anders te duur wordt","Vanwege klachten over geur","Om ruimte te maken voor nieuwe bakken"]}'::jsonb, '{"correctIndex":2,"explanation":"`Daarom` koppelt de klachten over geur aan de extra inzameling."}'::jsonb, 2
);

-- LUI-23 (B1) — Roosterprobleem in een team
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000053', 'B1', 'luisteren', 'Roosterprobleem in een team',
  'Je hoort een deel van een teamoverleg.', 123, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000053', 'listening_clip', 'Je hoort een deel van een teamoverleg.', '{"script":"Mariam: Ik wil woensdag graag naar de veiligheidstraining, maar ik sta dan op het rooster.\nJeroen: Ik kan jouw woensdag overnemen, alleen heb ik vrijdag een afspraak en dan zoek ik juist vervanging.\nMariam: Dan neem ik jouw vrijdagdienst over.\nTeamleider: Dat lijkt me een goede ruil. Zet het allebei in het roostersysteem, dan keur ik de wijziging vandaag goed."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000053', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Welke oplossing spreken de collega''s af?","options":["Mariam annuleert haar training","Jeroen werkt woensdag én vrijdag alleen","Mariam gaat woensdag naar de training en neemt vrijdag een dienst van Jeroen over","De manager sluit de afdeling op woensdag"]}'::jsonb, '{"correctIndex":2,"explanation":"De oplossing is een ruil van twee diensten."}'::jsonb, 2
);

-- LUI-24 (B2) — Meerdere oplossingen voor woningtekort
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000054', 'B2', 'luisteren', 'Meerdere oplossingen voor woningtekort',
  'Je hoort een fragment uit een podcast over wonen.', 124, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000054', 'listening_clip', 'Je hoort een fragment uit een podcast over wonen.', '{"script":"Het debat wordt vaak versmald tot de vraag hoeveel nieuwe woningen we in weilanden moeten bouwen. Natuurlijk is nieuwbouw nodig, maar daarmee zijn we er niet. Op sommige plekken kunnen leegstaande kantoren worden omgebouwd, grote woningen kunnen vrijwillig worden gesplitst en boven winkels is nog ruimte. Tegelijk duren vergunningprocedures lang, deels omdat belangen zorgvuldig moeten worden afgewogen. Wie één wonderoplossing belooft, onderschat dus de complexiteit. We hebben een pakket nodig: gerichte nieuwbouw, beter gebruik van bestaande gebouwen én procedures die sneller zijn zonder omwonenden buitenspel te zetten."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000054', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Wat is de centrale boodschap van de spreker?","options":["Alleen nieuwbouw aan de rand van steden kan het woningtekort oplossen","Het woningtekort vraagt om een combinatie van bouwen, verbouwen en snellere procedures","Leegstaande kantoren zijn vrijwel altijd ongeschikt als woning","Gemeenten moeten stoppen met inspraakprocedures"]}'::jsonb, '{"correctIndex":1,"explanation":"De spreker verwerpt één `wonderoplossing` en noemt expliciet een pakket van maatregelen."}'::jsonb, 2
);

-- LUI-25 (B2) — Toestemming en digitale privacy
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000055', 'B2', 'luisteren', 'Toestemming en digitale privacy',
  'Je hoort een fragment uit een lezing over digitale privacy.', 125, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000055', 'listening_clip', 'Je hoort een fragment uit een lezing over digitale privacy.', '{"script":"Veel digitale diensten verdedigen uitgebreide dataverzameling met de mededeling dat de gebruiker ermee heeft ingestemd. Maar die toestemming is niet automatisch betekenisvol. Mensen krijgen lange, technische teksten te zien en worden via opvallende knoppen richting `accepteren` gestuurd, terwijl weigeren meerdere stappen kost. Juridisch is er misschien een vinkje gezet, maar de keuze was niet noodzakelijk vrij of goed geïnformeerd. Daarom moet privacybescherming ook steunen op dataminimalisatie: verzamel niet méér dan voor de dienst werkelijk nodig is."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000055', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waarom vindt de spreker toestemming alleen onvoldoende als bescherming?","options":["Omdat gebruikers wettelijk nooit toestemming mogen geven","Omdat organisaties helemaal geen persoonsgegevens nodig hebben","Omdat keuzes vaak complex of sturend zijn, waardoor toestemming niet echt vrij en geïnformeerd is","Omdat privacyverklaringen altijd mondeling moeten worden gegeven"]}'::jsonb, '{"correctIndex":2,"explanation":"De spreker contrasteert een juridisch vinkje met een betekenisvolle keuze."}'::jsonb, 2
);

-- LUI-26 (B2) — Compromis over een autoluw centrum
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000056', 'B2', 'luisteren', 'Compromis over een autoluw centrum',
  'Je hoort een fragment uit een gemeenteraadsdebat.', 126, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000056', 'listening_clip', 'Je hoort een fragment uit een gemeenteraadsdebat.', '{"script":"Raadslid 1: Minder doorgaand verkeer maakt het centrum veiliger en aantrekkelijker. We moeten niet nog jaren wachten.\nRaadslid 2: Ondernemers vrezen dat leveringen moeilijker worden en klanten wegblijven. Een definitief besluit is daarom te vroeg.\nWethouder: Ik stel een proef van zes maanden voor. Tijdens die periode werken we met logistieke hubs aan de rand van het centrum en gratis bezorgfietsen voor deelnemende winkels. We meten bezoekersaantallen, omzetontwikkeling, luchtkwaliteit en bereikbaarheid. Daarna neemt de raad een definitief besluit."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
