-- LUI-27 (B2) — Functioneringsgesprek
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000057', 'B2', 'luisteren', 'Functioneringsgesprek',
  'Je hoort een deel van een functioneringsgesprek.', 127, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000057', 'listening_clip', 'Je hoort een deel van een functioneringsgesprek.', '{"script":"Manager: De inhoudelijke kwaliteit van je rapporten is hoog en klanten waarderen je zorgvuldigheid. Tegelijk lopen sommige opdrachten vertraging op, omdat je details blijft verbeteren die voor de beslissing niet doorslaggevend zijn.\nMedewerker: Ik herken dat. Soms weet ik niet goed wanneer `goed genoeg` echt goed genoeg is.\nManager: Laten we daarom vooraf beslismomenten afspreken. Bij twijfel bespreek je eerder met mij welke onderdelen prioriteit hebben. Het doel is niet dat je slordiger werkt, maar dat je je nauwkeurigheid inzet waar die de meeste waarde heeft."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000057', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Aan welk ontwikkeldoel gaat de medewerker vooral werken?","options":["Meer technische vakkennis verzamelen","Kwaliteit beter afwegen tegen snelheid en eerder prioriteiten bespreken","Alle rapporten zonder overleg volledig herschrijven","Minder samenwerken met collega''s"]}'::jsonb, '{"correctIndex":1,"explanation":"De manager wil de zorgvuldigheid behouden, maar gerichter inzetten."}'::jsonb, 2
);

-- LUI-28 (B2) — Voor- en nadelen van bevolkingsonderzoek
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000058', 'B2', 'luisteren', 'Voor- en nadelen van bevolkingsonderzoek',
  'Je hoort een medisch radioprogramma met algemene, niet-persoonlijke informatie.', 128, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000058', 'listening_clip', 'Je hoort een medisch radioprogramma met algemene, niet-persoonlijke informatie.', '{"script":"Vroege opsporing kan levens redden, maar het woord `vroeg` betekent niet vanzelf dat iedere gevonden afwijking behandeld moet worden. Sommige afwijkingen zouden nooit klachten veroorzaken. Toch kan de ontdekking leiden tot extra scans, onzekerheid of een ingreep met bijwerkingen. Daarnaast zijn er fout-positieve uitslagen: de test wijst dan op een probleem dat er uiteindelijk niet blijkt te zijn. Bij de beoordeling van een bevolkingsonderzoek moeten we dus zowel gezondheidswinst als mogelijke schade meewegen."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000058', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waarom is vroeg opsporen volgens de deskundige niet automatisch alleen maar gunstig?","options":["Omdat onderzoeken nooit betrouwbare resultaten geven","Omdat vroege opsporing behandeling altijd onmogelijk maakt","Omdat fout-positieve uitslagen en overdiagnose ook schade kunnen veroorzaken","Omdat alleen mensen met klachten onderzocht mogen worden"]}'::jsonb, '{"correctIndex":2,"explanation":"De spreker noemt onzekerheid, onnodig vervolgonderzoek en behandeling als mogelijke nadelen."}'::jsonb, 2
);

-- LUI-29 (B2) — Kunstmatige intelligentie en startersbanen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000059', 'B2', 'luisteren', 'Kunstmatige intelligentie en startersbanen',
  'Je hoort een arbeidsmarktdeskundige in een interview.', 129, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000059', 'listening_clip', 'Je hoort een arbeidsmarktdeskundige in een interview.', '{"script":"Ik verwacht niet dat kunstmatige intelligentie simpelweg complete beroepen wegvaagt. Waarschijnlijk verandert vooral de verdeling van taken. Mijn zorg zit bij startersfuncties: jonge medewerkers leren een vak vaak door eerst relatief routinematig werk te doen en geleidelijk complexere verantwoordelijkheid te krijgen. Als juist die instaptaken worden geautomatiseerd, kan de eerste trede van de ladder verdwijnen. Werkgevers zullen dan bewust andere leerplekken, traineeships en begeleide praktijkopdrachten moeten organiseren."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000059', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Waar maakt de deskundige zich vooral zorgen over?","options":["Dat binnen een jaar vrijwel alle beroepen verdwijnen","Dat werknemers geen enkele nieuwe vaardigheid kunnen leren","Dat routinetaken voor starters verdwijnen en daarmee ook een belangrijke leerroute","Dat alleen grote bedrijven technologie mogen gebruiken"]}'::jsonb, '{"correctIndex":2,"explanation":"De spreker relativeert massaal banenverlies en richt zich daarna op `de eerste trede van de ladder`."}'::jsonb, 2
);

-- LUI-30 (B2) — Bemiddeling tussen buren
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
