insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000060', 'listening_clip', 'Je hoort het slot van een bemiddelingsgesprek tussen twee buren.', '{"script":"Bemiddelaar: U begrijpt nu dat de kinderen normaal moeten kunnen spelen, maar ook dat meneer na zijn nachtdienst overdag moet slapen. Kunt u zich vinden in deze afspraken?\nBovenbuur: Ja. We leggen een dik kleed in de speelkamer en tussen twee en vier doen de kinderen daar rustige activiteiten.\nBenedenbuur: Dat helpt. Als ik een extra nachtdienst heb, stuur ik de avond ervoor een bericht. Bij onverwacht hard geluid app ik eerst, in plaats van meteen op de verwarming te tikken.\nBemiddelaar: Goed. Over een maand bespreken we of dit voldoende werkt."}'::jsonb, null, 1
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000060', 'multiple_choice', 'Kies het juiste antwoord.', '{"question":"Welke gezamenlijke afspraak komt uit het gesprek?","options":["De kinderen mogen thuis helemaal niet meer spelen","De benedenbuur verhuist naar een andere woning","Er komen geluiddempende maatregelen, vaste rustige uren en direct contact bij onverwachte overlast","Alleen de woningcorporatie mag nog met beide buren communiceren"]}'::jsonb, '{"correctIndex":2,"explanation":"Het akkoord bestaat uit meerdere wederzijdse aanpassingen en een evaluatiemoment."}'::jsonb, 2
);

