insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000069', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"De verwarming doet het sinds gisteren niet. Het is koud in huis en er woont een klein kind. Leg het probleem uit, vertel sinds wanneer het speelt en vraag wanneer een monteur kan komen.","expectedPoints":["soort storing","duur","extra urgentie","verzoek om monteur/tijd."],"modelAnswer":"Goedemorgen. Ik bel omdat de verwarming in mijn woning sinds gisteren niet meer werkt. Alle radiatoren blijven koud, ook als ik de thermostaat hoger zet. Er woont een kind van twee jaar bij ons, dus ik wil graag dat er snel iemand komt kijken. Wanneer kan een monteur langskomen?"}'::jsonb, null, 1
);

-- SPR-10 (A2) — Gesprek met de leerkracht
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
