insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000070', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je kind vindt rekenen moeilijk en maakt thuis vaak ruzie over huiswerk. Leg uit wat je thuis merkt en vraag hoe school kan helpen.","expectedPoints":["probleem met rekenen","gedrag thuis","minstens één vraag om informatie of hulp."],"modelAnswer":"Ik merk dat Noor rekenen erg moeilijk vindt. Bij het huiswerk wordt ze snel boos en ze zegt dat ze de uitleg niet begrijpt. Gebeurt dat op school ook? Kunt u vertellen wat we thuis kunnen oefenen en of zij misschien extra hulp kan krijgen?"}'::jsonb, null, 1
);

-- SPR-11 (A2) — Een product terugbrengen
