insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000071', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je hebt drie dagen geleden een waterkoker gekocht. Hij gaat niet aan. Je hebt de bon. Leg het probleem uit en zeg welke oplossing je wilt.","expectedPoints":["aankoopmoment","defect","bon","gewenste oplossing."],"modelAnswer":"Goedemiddag. Ik heb deze waterkoker drie dagen geleden hier gekocht, maar hij gaat niet aan. Ik heb verschillende stopcontacten geprobeerd en hij werkt nog steeds niet. Hier is de bon. Ik wil hem graag omruilen voor een nieuw exemplaar. Kan dat?"}'::jsonb, null, 1
);

-- SPR-12 (A2) — De route naar je huis uitleggen
