insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000072', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je woont tien minuten lopen van het station. Geef een duidelijke route met minstens drie stappen en één herkenningspunt.","expectedPoints":["minimaal drie routehandelingen","een herkenningspunt."],"modelAnswer":"Als je het station uitkomt, ga je linksaf. Loop rechtdoor tot het tweede verkeerslicht en steek daar de weg over. Daarna neem je de eerste straat rechts. Mijn huis is na ongeveer honderd meter aan de linkerkant, tegenover de bakker."}'::jsonb, null, 1
);

-- SPR-13 (A2) — Een dienst ruilen
