insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000073', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je moet vrijdag naar een afspraak in het ziekenhuis. Je wilt jouw vrijdagavonddienst ruilen voor de zaterdagochtenddienst van je collega. Leg de reden uit, stel de ruil voor en vraag of de collega akkoord gaat.","expectedPoints":["reden","concrete ruil","vraag om akkoord."],"modelAnswer":"Heb je even tijd? Ik heb vrijdagmiddag een afspraak in het ziekenhuis en daardoor kan ik mijn avonddienst niet werken. Zou jij mijn dienst vrijdagavond kunnen overnemen? Dan neem ik jouw dienst van zaterdagochtend over. Past dat voor jou?"}'::jsonb, null, 1
);

