);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000077', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je hebt ervaring in een winkel en solliciteert naar een baan bij een klantenservice. Leg uit waarom je de functie wilt, welke ervaring relevant is en geef een voorbeeld van hoe je met een ontevreden klant omgaat.","expectedPoints":["motivatie","relevante ervaring","concreet voorbeeld met aanpak/resultaat."],"modelAnswer":"Ik wil deze functie graag omdat ik het leuk vind om mensen te helpen en problemen op te lossen. In mijn vorige baan in een elektronicawinkel had ik dagelijks contact met klanten. Daardoor heb ik geleerd rustig te blijven en goed door te vragen. Een klant was bijvoorbeeld boos omdat een bestelling te laat was. Ik heb eerst geluisterd, daarna gecontroleerd waar het pakket was en uiteindelijk gratis bezorging voor een nieuwe afspraak geregeld. De klant waardeerde vooral dat ik duidelijk uitlegde wat ik wel en niet kon doen. Die ervaring past volgens mij goed bij klantenservice."}'::jsonb, null, 1
);

-- SPR-18 (B1) — Mening over goedkoper openbaar vervoer
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000078', 'B1', 'spreken', 'Mening over goedkoper openbaar vervoer',
  'De stelling is: `Openbaar vervoer moet in steden veel goedkoper worden.`', 118, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000078', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"De stelling is: `Openbaar vervoer moet in steden veel goedkoper worden.` Geef je mening, noem twee argumenten en reageer op het bezwaar dat de maatregel veel geld kost.","expectedPoints":["duidelijk standpunt","twee argumenten","reactie op kostenbezwaar."],"modelAnswer":"Ik ben voor goedkoper openbaar vervoer in grote steden. Ten eerste kunnen mensen met een laag inkomen dan makkelijker naar werk, school of een afspraak. Ten tweede kan het autoverkeer afnemen, waardoor de lucht schoner en de straten veiliger worden. Natuurlijk kost een lagere prijs de overheid geld. Toch denk ik dat een deel daarvan wordt terugverdiend door minder files en mogelijk minder kosten door luchtvervuiling. Ik zou wel beginnen met korting voor bepaalde groepen en buiten de spits, zodat we eerst kunnen meten wat het effect is."}'::jsonb, null, 1
);

-- SPR-19 (B1) — Vocht en schimmel in de woning
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000079', 'B1', 'spreken', 'Vocht en schimmel in de woning',
  'In de slaapkamer zit steeds meer schimmel. Je ventileert dagelijks, maar het probleem komt terug.', 119, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000079', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"In de slaapkamer zit steeds meer schimmel. Je ventileert dagelijks, maar het probleem komt terug. Beschrijf het probleem en de gevolgen, vertel wat je zelf hebt geprobeerd en vraag om een concrete vervolgstap.","expectedPoints":["plaats","aard probleem","gevolgen","eigen acties","verzoek om onderzoek/afspraak."],"modelAnswer":"Ik wil een terugkerend vochtprobleem in de slaapkamer melden. In de hoek bij het raam ontstaat steeds opnieuw zwarte schimmel. Ik ventileer iedere ochtend en heb de plek al twee keer schoongemaakt, maar na een paar weken komt de schimmel terug. Mijn dochter slaapt in die kamer en hoest de laatste tijd vaker, dus ik maak me zorgen. Ik wil graag dat iemand onderzoekt waar het vocht vandaan komt en niet alleen de muur opnieuw schildert. Wanneer kan een inspecteur langskomen?"}'::jsonb, null, 1
);

-- SPR-20 (B1) — Wachttijd voor klanten verminderen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000080', 'B1', 'spreken', 'Wachttijd voor klanten verminderen',
  'Klanten wachten aan het begin van de middag vaak te lang aan de balie.', 120, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000080', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Klanten wachten aan het begin van de middag vaak te lang aan de balie. Doe een voorstel, leg uit waarom het kan werken en noem één mogelijk nadeel met een oplossing.","expectedPoints":["concreet voorstel","verwachte werking","nadeel","oplossing/evaluatie."],"modelAnswer":"Ik stel voor dat we tussen twaalf en twee met een flexibel rooster werken. Op drukke dagen kan één collega tijdelijk van de administratie naar de balie gaan. Daardoor kunnen we sneller een tweede loket openen en worden de rijen korter. Een nadeel is dat administratief werk dan kan blijven liggen. We kunnen dat beperken door vooraf af te spreken welke taken echt dezelfde dag af moeten en door na twee uur een rustig blok voor administratie te plannen. Laten we dit vier weken testen en de gemiddelde wachttijd meten."}'::jsonb, null, 1
);

-- SPR-21 (B1) — Een fietsongeluk beschrijven
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000081', 'B1', 'spreken', 'Een fietsongeluk beschrijven',
  'Je bent op de fiets aangereden door een auto. Niemand raakte ernstig gewond, maar je fiets is beschadigd.', 121, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000081', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je bent op de fiets aangereden door een auto. Niemand raakte ernstig gewond, maar je fiets is beschadigd. Vertel chronologisch wat er gebeurde, welke schade er is en welke informatie je hebt verzameld.","expectedPoints":["tijd/plaats","toedracht","letsel/schade","verzamelde gegevens."],"modelAnswer":"Gisteren rond vijf uur fietste ik op de rotonde bij de Parklaan. Een auto wilde de rotonde verlaten en zag mij waarschijnlijk te laat. De auto raakte mijn achterwiel, waardoor ik viel. Ik heb alleen een blauwe plek, maar het achterwiel en de bagagedrager zijn verbogen. We hebben samen het schadeformulier ingevuld en ik heb foto''s gemaakt van de situatie en van het kenteken. Ook heeft een voorbijganger zijn telefoonnummer gegeven als getuige. Ik wil graag weten welke documenten u verder nodig hebt."}'::jsonb, null, 1
);

-- SPR-22 (B1) — Twee cursussen vergelijken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000082', 'B1', 'spreken', 'Twee cursussen vergelijken',
  'Cursus A is twee avonden per week, goedkoop en duurt zes maanden. Cursus B is drie ochtenden per week, duurder en duurt drie maanden. Je werkt overdag en wilt snel B1 halen.', 122, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000082', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Cursus A is twee avonden per week, goedkoop en duurt zes maanden. Cursus B is drie ochtenden per week, duurder en duurt drie maanden. Je werkt overdag en wilt snel B1 halen. Vergelijk de opties, kies één cursus en leg uit welke afweging je maakt.","expectedPoints":["voor-","nadelen van beide opties","keuze","voorwaarde/afweging."],"modelAnswer":"Cursus A is makkelijker met mijn werk te combineren, omdat de lessen ''s avonds zijn. Bovendien is die cursus goedkoper. Het nadeel is dat hij zes maanden duurt, terwijl ik mijn B1-niveau graag snel wil halen. Cursus B is intensiever en duurt maar drie maanden, maar de lessen zijn in de ochtend en dan werk ik normaal. Ik zou toch voor cursus A kiezen, tenzij mijn werkgever mij tijdelijk drie ochtenden vrij kan geven. Zonder zo''n afspraak is cursus B niet realistisch, ook al gaat die sneller."}'::jsonb, null, 1
);

-- SPR-23 (B1) — Buurtactie presenteren
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000083', 'B1', 'spreken', 'Buurtactie presenteren',
  'Je organiseert een gezamenlijke schoonmaakactie in het park.', 123, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000083', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je organiseert een gezamenlijke schoonmaakactie in het park. Geef een korte presentatie van ongeveer één minuut. Noem het probleem, het plan, wat deelnemers moeten meenemen en hoe mensen zich aanmelden.","expectedPoints":["probleem","datum/tijd","plan","benodigdheden","aanmelding."],"modelAnswer":"In het park ligt de laatste maanden veel afval, vooral rond de speelplaats en de vijver. Daarom organiseren we op zaterdag 18 mei van tien tot twaalf uur een schoonmaakactie. We verdelen het park in kleine gebieden en de gemeente haalt de volle zakken na afloop op. Handschoenen en afvalgrijpers zijn beschikbaar, maar neem zelf stevige schoenen en eventueel een regenjas mee. Kinderen mogen meedoen onder begeleiding van een volwassene. Aanmelden kan tot 15 mei via de buurtapp. Na afloop drinken we samen koffie en thee in het buurthuis."}'::jsonb, null, 1
);

-- SPR-24 (B2) — Vierdaagse werkweek bespreken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000084', 'B2', 'spreken', 'Vierdaagse werkweek bespreken',
  'Je organisatie overweegt een proef met vier dagen werken tegen hetzelfde salaris, met behoud van afgesproken resultaten.', 124, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000084', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je organisatie overweegt een proef met vier dagen werken tegen hetzelfde salaris, met behoud van afgesproken resultaten. Geef een genuanceerd standpunt. Bespreek voordelen, risico''s, voorwaarden voor een proef en hoe succes gemeten kan worden.","expectedPoints":["genuanceerd standpunt","voordelen","risico''s","voorwaarden","meerdere meetcriteria."],"modelAnswer":"Ik vind een proef verdedigbaar, maar alleen wanneer we niet vooraf aannemen dat hetzelfde model voor iedere functie werkt. Een mogelijke winst is dat medewerkers beter herstellen en daardoor geconcentreerder zijn. Dat kan ziekteverzuim en verloop beperken. Tegelijk bestaat het risico dat vijf dagen werk simpelweg in vier langere, intensievere dagen wordt geperst. Dan verschuiven we de werkdruk in plaats van haar te verminderen. Ik zou daarom met vrijwillige teams en een nulmeting beginnen. We moeten niet alleen productiviteit volgen, maar ook werkdruk, kwaliteit, bereikbaarheid voor klanten en samenwerking tussen functies. Daarnaast moet duidelijk zijn welke werkzaamheden vervallen of efficiënter worden ingericht. Na zes maanden kunnen werknemers én klanten worden bevraagd. Pas als de resultaten op meerdere indicatoren positief zijn, zou bredere invoering verantwoord zijn."}'::jsonb, null, 1
);

-- SPR-25 (B2) — Onderhandelen over langdurige reparatie
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000085', 'B2', 'spreken', 'Onderhandelen over langdurige reparatie',
  'Door een lekkage is één kamer zes weken nauwelijks bruikbaar. De verhuurder heeft gerepareerd, maar veel later dan aanvankelijk beloofd. Je wilt een redelijke compensatie.', 125, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000085', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Door een lekkage is één kamer zes weken nauwelijks bruikbaar. De verhuurder heeft gerepareerd, maar veel later dan aanvankelijk beloofd. Je wilt een redelijke compensatie. Leg je positie feitelijk uit, formuleer een concreet verzoek, reageer op een lager tegenvoorstel en probeer tot een afspraak te komen.","expectedPoints":["feiten/tijdlijn","gevolgen","concreet verzoek","reactie op tegenvoorstel","compromis."],"modelAnswer":"Ik waardeer dat de lekkage inmiddels is verholpen, maar de afhandeling heeft aanzienlijk langer geduurd dan de aangekondigde twee weken. Zes weken lang konden we de slaapkamer nauwelijks gebruiken en hebben we extra kosten gemaakt voor een ontvochtiger en tijdelijk slapen elders. Ik verzoek daarom om vergoeding van de aantoonbare extra kosten en om een evenredige tegemoetkoming in de huur over de periode waarin de kamer niet normaal bruikbaar was. Uw voorstel om alleen de stroomkosten van de ontvochtiger te vergoeden vind ik te beperkt, omdat daarmee het verlies van woongenot buiten beschouwing blijft. Ik ben bereid een gematigde vaste tegemoetkoming te accepteren als daarnaast alle bonnetjes worden vergoed en de resterende schilderwerkzaamheden vóór een concrete datum worden uitgevoerd. Kunnen we die combinatie vastleggen?"}'::jsonb, null, 1
);

-- SPR-26 (B2) — Sociale media en privacy
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000086', 'B2', 'spreken', 'Sociale media en privacy',
  'De stelling is: `Gebruikers zijn zelf verantwoordelijk voor de gegevens die sociale media verzamelen.`', 126, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000086', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"De stelling is: `Gebruikers zijn zelf verantwoordelijk voor de gegevens die sociale media verzamelen.` Reageer op de stelling, onderscheid individuele en bedrijfsmatige verantwoordelijkheid en gebruik minstens één concreet voorbeeld.","expectedPoints":["eigen positie","gedeelde maar ongelijke verantwoordelijkheid","voorbeeld","conclusie."],"modelAnswer":"Gebruikers dragen enige verantwoordelijkheid: zij kunnen privacy-instellingen controleren en voorzichtig zijn met wat zij openbaar plaatsen. Toch vind ik het onjuist om de hoofdverantwoordelijkheid volledig bij hen te leggen. Platforms ontwerpen de keuzeomgeving, bepalen welke gegevens standaard worden verzameld en beschikken over veel meer technische kennis dan de gemiddelde gebruiker. Wanneer `alles accepteren` één duidelijke knop is en weigeren via vijf schermen loopt, is de keuze formeel vrijwillig maar praktisch gestuurd. Bovendien worden ook gedragsgegevens afgeleid die iemand nooit bewust heeft ingevuld, zoals vermoedelijke interesses of kwetsbaarheden. Daarom moeten bedrijven gegevensverzameling beperken tot wat nodig is, keuzes begrijpelijk maken en geen nadelige gevolgen verbinden aan onnodige weigering. Individuele voorzichtigheid blijft nuttig, maar kan structurele bescherming niet vervangen."}'::jsonb, null, 1
);

-- SPR-27 (B2) — Conflict tussen collega's bemiddelen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000087', 'B2', 'spreken', 'Conflict tussen collega''s bemiddelen',
  'Collega A vindt dat collega B afspraken te laat doorgeeft. Collega B vindt dat A te controlerend communiceert. Jij bent teamcoördinator.', 127, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000087', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Collega A vindt dat collega B afspraken te laat doorgeeft. Collega B vindt dat A te controlerend communiceert. Jij bent teamcoördinator. Open het gesprek neutraal, vat beide perspectieven samen, stel verhelderende vragen en formuleer een werkbare afspraak.","expectedPoints":["neutrale opening","beide belangen","verheldering","concrete wederzijdse afspraak/evaluatie."],"modelAnswer":"Ik wil eerst vaststellen dat jullie allebei last hebben van de huidige samenwerking, maar het probleem verschillend ervaren. Voor A ontstaat stress wanneer wijzigingen pas laat bekend zijn, omdat het rooster dan moeilijk aan te passen is. B ervaart de vele controlevragen juist als wantrouwen en krijgt daardoor minder ruimte om zelfstandig te werken. Klopt die samenvatting? Ik wil vervolgens concreet weten om welke soorten wijzigingen het gaat en hoeveel voorbereidingstijd redelijk is. Mijn voorstel is dat roosterwijzigingen uiterlijk twee werkdagen vooraf in één gedeeld kanaal worden gemeld. Alleen bij spoed volgt daarnaast een telefoontje. A controleert niet tussendoor via meerdere berichten, maar kijkt op twee vaste momenten per dag. Na drie weken bespreken we of deze afspraak zowel duidelijkheid als zelfstandigheid oplevert."}'::jsonb, null, 1
);

-- SPR-28 (B2) — Beleidsadvies voor veilig fietsen
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000088', 'B2', 'spreken', 'Beleidsadvies voor veilig fietsen',
  'Rond een middelbare school ontstaan ''s ochtends gevaarlijke situaties door auto''s, fietsen en bezorgverkeer.', 128, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000088', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Rond een middelbare school ontstaan ''s ochtends gevaarlijke situaties door auto''s, fietsen en bezorgverkeer. Presenteer een samenhangend advies met korte- en langetermijnmaatregelen, mogelijke bezwaren en evaluatiecriteria.","expectedPoints":["korte termijn","lange termijn","bezwaren/belangen","meetbare evaluatie."],"modelAnswer":"Ik adviseer een combinatie van directe verkeersmaatregelen en een structurele herinrichting. Op korte termijn kan de straat tijdens de begin- en eindtijden als schoolstraat worden afgesloten voor doorgaand autoverkeer. Voor ouders die echt met de auto moeten komen, richten we op enige afstand een duidelijke uitstapzone in. Bezorgverkeer krijgt een tijdvenster buiten de drukste momenten. Op langere termijn zijn een bredere fietsstrook, betere verlichting en een fysiek gescheiden oversteekplaats nodig. Ondernemers zullen mogelijk vrezen voor slechtere bereikbaarheid; daarom moeten laad- en lostijden in overleg worden vastgelegd. Ook moeten uitzonderingen voor hulpdiensten en mensen met een mobiliteitsbeperking praktisch uitvoerbaar zijn. We evalueren na drie maanden op bijna-ongevallen, verkeersdruk, reistijd en ervaringen van leerlingen, omwonenden en ondernemers."}'::jsonb, null, 1
);

-- SPR-29 (B2) — Kritische vragen over een opleidingsplan
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000089', 'B2', 'spreken', 'Kritische vragen over een opleidingsplan',
  'Jij stelt voor dat alle teamleiders een tweedaagse training in feedbackgesprekken volgen. Het kost tijd en geld.', 129, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000089', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Jij stelt voor dat alle teamleiders een tweedaagse training in feedbackgesprekken volgen. Het kost tijd en geld. Presenteer het voorstel kort en reageer overtuigend op de bezwaren `te duur`, `te algemeen` en `geen tijd`.","expectedPoints":["voorstel","antwoord op alle drie bezwaren","evaluatie/stopcriterium."],"modelAnswer":"Het voorstel is een tweedaagse training met praktijkcases uit onze eigen organisatie, gevolgd door twee korte intervisiesessies. De kosten zijn zichtbaar, maar gebrekkige feedback kost eveneens geld via misverstanden, verloop en langdurige conflicten. Om te voorkomen dat de training te algemeen blijft, verzamelen we vooraf echte gesprekssituaties en laten we deelnemers met hun eigen casus oefenen. Het tijdsbezwaar is terecht; daarom plan ik de dagen verspreid en niet in onze drukste periode. Bovendien nemen we na drie maanden een steekproef van gespreksverslagen en vragen we medewerkers of verwachtingen duidelijker worden besproken. Wanneer daar geen verbetering uit blijkt, passen we het programma aan of stoppen we met de vervolgmodule. Het is dus geen vrijblijvende cursus, maar een gerichte interventie met meetbare opbrengsten."}'::jsonb, null, 1
);

-- SPR-30 (B2) — Samenvatten en beoordelen van een tekst
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000090', 'B2', 'spreken', 'Samenvatten en beoordelen van een tekst',
  'Je krijgt de volgende inhoudskaart:', 130, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000090', 'speaking_prompt', 'Oefen hardop.', '{"scenario":"Je krijgt de volgende inhoudskaart: Vat de kern samen, benoem het belangrijkste voordeel en risico en geef je eigen oordeel over de voorgestelde waarborgen.","expectedPoints":["correcte samenvatting","voordeel","risico","beargumenteerde beoordeling van waarborgen."],"modelAnswer":"De tekst gaat over een bedrijf dat kunstmatige intelligentie inzet om sollicitatiebrieven voor te selecteren. Het voornaamste voordeel is efficiëntie: HR kan sneller een grote hoeveelheid brieven verwerken. Het centrale risico is dat het systeem vooroordelen uit historische gegevens overneemt en daardoor bepaalde groepen structureel benadeelt. De voorgestelde waarborgen—menselijke controle, transparantie richting kandidaten en periodieke tests—zijn noodzakelijk, maar volgens mij nog niet volledig. Menselijke controle heeft alleen waarde als medewerkers werkelijk van het advies mogen afwijken en daarvoor voldoende tijd krijgen. Ook moet vooraf worden vastgesteld welke verschillen tussen groepen onaanvaardbaar zijn en wat er gebeurt als een test problemen laat zien. Ten slotte verdient een afgewezen kandidaat ten minste een begrijpelijke uitleg over de doorslaggevende criteria, zonder dat het bedrijf ieder technisch detail hoeft prijs te geven."}'::jsonb, null, 1
);

-- SCH-1 (A1) — Inschrijfformulier taalcafé
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000091', 'A1', 'schrijven', 'Inschrijfformulier taalcafé',
  'Je schrijft je in voor een taalcafé.', 101, true
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000091', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je schrijft je in voor een taalcafé. Vul de velden in met verzonnen of eigen gegevens.\n\n- Voornaam\n- Achternaam\n- Geboortedatum\n- Adres\n- Telefoonnummer\n- E-mailadres\n- Welke taal spreek je thuis?\n- Welke avond kun je komen: dinsdag of donderdag?","modelAnswer":"Voornaam: Amina\nAchternaam: El Amrani\nGeboortedatum: 14-09-1992\nAdres: Langestraat 18, 3512 AB Utrecht\nTelefoonnummer: 06 12345678\nE-mailadres: amina.voorbeeld@example.com\nTaal thuis: Arabisch\nBeschikbare avond: donderdag"}'::jsonb, null, 1
);

-- SCH-2 (A1) — Te laat voor de les
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000092', 'A1', 'schrijven', 'Te laat voor de les',
  'De bus heeft vertraging. Je bent ongeveer vijftien minuten te laat voor de Nederlandse les.', 102, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000092', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De bus heeft vertraging. Je bent ongeveer vijftien minuten te laat voor de Nederlandse les. Schrijf een bericht van 20-35 woorden aan je docent. Noem:\n\n- dat je te laat bent\n- waarom\n- hoeveel minuten later je komt","minWords":20,"modelAnswer":"Hallo mevrouw De Jong, mijn bus heeft vertraging. Daarom ben ik vandaag ongeveer vijftien minuten te laat voor de les. Sorry, ik kom zo snel mogelijk. Groet, Rami"}'::jsonb, null, 1
);

