insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000095', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je hebt sinds twee dagen pijn aan je oor en wilt morgenochtend een afspraak. Schrijf 25-45 woorden. Noem je klacht, de duur en wanneer je kunt.","minWords":25,"modelAnswer":"Beste assistent, ik heb sinds twee dagen pijn aan mijn rechteroor. Ik wil graag een afspraak bij de huisarts. Kan ik morgenochtend komen? Mijn telefoonnummer is 06 12345678. Met vriendelijke groet, Omar Ali"}'::jsonb, null, 1
);

-- SCH-6 (A1) — Boodschap voor een huisgenoot
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
