insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000097', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je zoon Adam heeft koorts en komt vandaag niet naar school. Schrijf 20-40 woorden. Noem naam, reden en dag.","minWords":20,"modelAnswer":"Goedemorgen, mijn zoon Adam uit groep 5 heeft koorts. Daarom komt hij vandaag niet naar school. Ik laat morgen weten hoe het met hem gaat. Groet, mevrouw Hassan"}'::jsonb, null, 1
