-- SCH-8 (A1) — Kort persoonlijk profiel
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000098', 'A1', 'schrijven', 'Kort persoonlijk profiel',
  'Je maakt een profiel voor een taalmaatjeswebsite.', 108, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000098', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je maakt een profiel voor een taalmaatjeswebsite. Schrijf 40-60 woorden. Vertel:\n\n- wie je bent\n- waar je woont\n- waarom je Nederlands oefent\n- wat je graag samen wilt doen","minWords":40,"modelAnswer":"Ik heet Luis en ik ben 34 jaar. Ik woon sinds kort in Eindhoven. Ik wil beter Nederlands spreken voor mijn werk en voor contact met buren. Ik zoek een taalmaatje dat één keer per week wil wandelen of koffie drinken en met mij wil praten."}'::jsonb, null, 1
);

-- SCH-9 (A2) — Kapotte wasmachine melden
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000099', 'A2', 'schrijven', 'Kapotte wasmachine melden',
  'De wasmachine die bij de huurwoning hoort, pompt het water niet weg. Je hebt het filter gecontroleerd.', 109, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000099', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De wasmachine die bij de huurwoning hoort, pompt het water niet weg. Je hebt het filter gecontroleerd. Schrijf 60-90 woorden. Noem:\n\n- wat er niet werkt\n- sinds wanneer\n- wat je zelf hebt geprobeerd\n- wanneer je thuis bent voor een monteur","minWords":60,"modelAnswer":"Geachte heer/mevrouw,\nSinds gisteren pompt de wasmachine in mijn huurwoning het water niet meer weg. Na het programma blijft de trommel vol water staan. Ik heb de machine uitgezet en het filter volgens de handleiding gecontroleerd, maar dat heeft niet geholpen. Kunt u een monteur sturen? Dinsdag en donderdag ben ik na 13.00 uur thuis.\nMet vriendelijke groet,\nSalma Idrissi"}'::jsonb, null, 1
);

-- SCH-10 (A2) — Tandartsafspraak verzetten
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000100', 'A2', 'schrijven', 'Tandartsafspraak verzetten',
  'Je afspraak is maandag 8 juli om 11.00 uur. Door een werkvergadering kun je niet. Woensdag na 15.00 uur of vrijdag vóór 12.00 uur kan wel.', 110, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000100', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je afspraak is maandag 8 juli om 11.00 uur. Door een werkvergadering kun je niet. Woensdag na 15.00 uur of vrijdag vóór 12.00 uur kan wel. Schrijf 60-90 woorden met de oude afspraak, reden en twee alternatieven.","minWords":60,"modelAnswer":"Beste assistent,\nIk heb op maandag 8 juli om 11.00 uur een afspraak bij tandarts Van Dijk. Helaas kan ik dan niet komen, omdat ik op mijn werk een verplichte vergadering heb. Kunt u de afspraak verzetten? Ik kan woensdag na 15.00 uur of vrijdag vóór 12.00 uur. Wilt u laten weten of één van deze momenten mogelijk is?\nMet vriendelijke groet,\nPavel Novak"}'::jsonb, null, 1
);

-- SCH-11 (A2) — Uitnodiging voor een verjaardag
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000101', 'A2', 'schrijven', 'Uitnodiging voor een verjaardag',
  'Je viert op zaterdag 22 augustus vanaf 16.00 uur je verjaardag in het buurthuis. Gasten moeten vóór 15 augustus laten weten of ze komen.', 111, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000101', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je viert op zaterdag 22 augustus vanaf 16.00 uur je verjaardag in het buurthuis. Gasten moeten vóór 15 augustus laten weten of ze komen. Schrijf 60-90 woorden. Noem datum, tijd, plaats, eten/drinken en antwoorddatum.","minWords":60,"modelAnswer":"Hoi allemaal,\nOp zaterdag 22 augustus vier ik mijn verjaardag in buurthuis De Brug, Kerkstraat 12. Jullie zijn welkom vanaf 16.00 uur. Er is eten en drinken, dus je hoeft niets mee te nemen. Laat je vóór 15 augustus weten of je komt? Dan weet ik voor hoeveel mensen ik moet bestellen. Ik hoop jullie te zien!\nGroetjes,\nElena"}'::jsonb, null, 1
);

-- SCH-12 (A2) — Vrij vragen op het werk
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000102', 'A2', 'schrijven', 'Vrij vragen op het werk',
  'Je wilt vrijdag 4 oktober vrij voor een familieafspraak. Je collega Amir kan jouw ochtenddienst overnemen.', 112, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000102', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je wilt vrijdag 4 oktober vrij voor een familieafspraak. Je collega Amir kan jouw ochtenddienst overnemen. Schrijf 60-90 woorden. Noem reden, datum, voorgestelde vervanging en vraag om akkoord.","minWords":60,"modelAnswer":"Beste Marieke,\nIk wil graag op vrijdag 4 oktober een vrije dag opnemen vanwege een belangrijke familieafspraak. Ik heb al met Amir overlegd en hij kan mijn ochtenddienst overnemen. Ik kan zijn dienst op maandagavond terugnemen, zodat het rooster compleet blijft. Kun je laten weten of je hiermee akkoord gaat?\nMet vriendelijke groet,\nBilal"}'::jsonb, null, 1
);

-- SCH-13 (A2) — Verloren tas melden
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000103', 'A2', 'schrijven', 'Verloren tas melden',
  'Je bent gisteren in bus 24 een zwarte rugtas vergeten. In de tas zitten een blauw notitieboek, een groene lunchbox en huissleutels.', 113, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000103', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je bent gisteren in bus 24 een zwarte rugtas vergeten. In de tas zitten een blauw notitieboek, een groene lunchbox en huissleutels. Schrijf 70-100 woorden. Beschrijf plaats/tijd, tas, inhoud en contactgegevens.","minWords":70,"modelAnswer":"Gisteren, dinsdag 6 mei, ben ik rond 17.30 uur mijn zwarte rugtas vergeten in bus 24 richting Centraal Station. Ik zat achterin, aan de rechterkant. De tas is middelgroot en heeft een klein wit logo aan de voorkant. Er zitten een blauw notitieboek, een groene lunchbox en een sleutelbos met drie sleutels in. Heeft u de tas gevonden? U kunt mij bereiken via 06 12345678 of l.ahmed@example.com."}'::jsonb, null, 1
);

-- SCH-14 (A2) — Reageren op onderhoudsafspraak
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000104', 'A2', 'schrijven', 'Reageren op onderhoudsafspraak',
  'De woningcorporatie wil woensdag tussen 08.00 en 12.00 uur langskomen. Je werkt dan. Donderdagmiddag ben je thuis; anders kan buurvrouw op nummer 18 de sleutel geven.', 114, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000104', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De woningcorporatie wil woensdag tussen 08.00 en 12.00 uur langskomen. Je werkt dan. Donderdagmiddag ben je thuis; anders kan buurvrouw op nummer 18 de sleutel geven. Schrijf 60-90 woorden met beide oplossingen.","minWords":60,"modelAnswer":"Geachte heer/mevrouw,\nBedankt voor uw bericht. Woensdag tussen 08.00 en 12.00 uur kan ik helaas niet thuis zijn, omdat ik dan werk. Donderdagmiddag ben ik wel beschikbaar. Als de afspraak niet kan worden verplaatst, kan mijn buurvrouw op nummer 18 de sleutel aan de monteur geven. Wilt u laten weten welke oplossing u kiest?\nMet vriendelijke groet,\nM. Kaya"}'::jsonb, null, 1
);

-- SCH-15 (A2) — Eerder weg van school
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000105', 'A2', 'schrijven', 'Eerder weg van school',
  'Je dochter Mila heeft donderdag om 14.30 uur een afspraak bij de oogarts en moet om 14.00 uur worden opgehaald. Haar oom komt haar halen.', 115, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000105', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je dochter Mila heeft donderdag om 14.30 uur een afspraak bij de oogarts en moet om 14.00 uur worden opgehaald. Haar oom komt haar halen. Schrijf 50-80 woorden. Noem reden, ophaaltijd en naam/rol van de ophaler.","minWords":50,"modelAnswer":"Beste meester Tom,\nMila heeft donderdag om 14.30 uur een afspraak bij de oogarts. Daarom moet zij die dag om 14.00 uur uit de klas worden opgehaald. Ik kan zelf niet komen; haar oom, Hassan El Idrissi, haalt haar op. Wilt u dit bij de administratie doorgeven?\nAlvast bedankt,\nNadia El Idrissi"}'::jsonb, null, 1
);

-- SCH-16 (A2) — Korte beoordeling van een taalcursus
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000106', 'A2', 'schrijven', 'Korte beoordeling van een taalcursus',
  'Je hebt zes weken een avondcursus Nederlands gevolgd. De docent legde duidelijk uit, de groep was prettig, maar er was weinig spreektijd.', 116, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000106', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je hebt zes weken een avondcursus Nederlands gevolgd. De docent legde duidelijk uit, de groep was prettig, maar er was weinig spreektijd. Schrijf 80-110 woorden. Noem twee positieve punten, één verbeterpunt en of je de cursus aanbeveelt.","minWords":80,"modelAnswer":"Ik heb zes weken de avondcursus Nederlands gevolgd en ben over het algemeen tevreden. De docent legde de grammatica duidelijk uit en gaf snel antwoord op vragen. Ook was de sfeer in de groep vriendelijk, waardoor ik me op mijn gemak voelde. Een verbeterpunt is de spreektijd: er waren veel cursisten, dus we konden niet vaak lang oefenen. Ik zou meer werk in kleine groepjes prettig vinden. Toch raad ik de cursus aan, vooral aan mensen die hun basisgrammatica willen verbeteren."}'::jsonb, null, 1
);

-- SCH-17 (B1) — Formele klacht over internet
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000107', 'B1', 'schrijven', 'Formele klacht over internet',
  'Je internet valt sinds drie weken dagelijks uit. De helpdesk beloofde twee keer terug te bellen, maar deed dat niet. Je werkt thuis.', 117, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000107', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je internet valt sinds drie weken dagelijks uit. De helpdesk beloofde twee keer terug te bellen, maar deed dat niet. Je werkt thuis. Schrijf 130-180 woorden. Beschrijf de tijdlijn, gevolgen, eerdere contacten en gewenste oplossing met redelijke termijn.","minWords":130,"modelAnswer":"**Onderwerp: aanhoudende internetstoring en uitblijven van reactie**\n\nGeachte heer/mevrouw,\n\nSinds drie weken valt mijn internetverbinding iedere dag meerdere keren uit. Vooral tussen 09.00 en 12.00 uur is de verbinding instabiel. Omdat ik drie dagen per week thuiswerk, kan ik daardoor niet betrouwbaar deelnemen aan online vergaderingen.\n\nOp 4 en 9 maart heb ik hierover contact opgenomen met uw helpdesk. Beide medewerkers beloofden dat een technische afdeling mij binnen twee werkdagen zou terugbellen, maar ik heb nog geen reactie ontvangen. Ik heb het modem volgens uw instructies opnieuw gestart en alle kabels gecontroleerd; het probleem blijft bestaan.\n\nIk verzoek u binnen vijf werkdagen een monteur in te plannen of schriftelijk een andere concrete oplossing te bieden. Daarnaast ontvang ik graag informatie over een passende vergoeding voor de periode waarin de dienst niet goed functioneerde.\n\nMet vriendelijke groet,\nSofia Marin"}'::jsonb, null, 1
);

-- SCH-18 (B1) — Motivatiebrief voor logistiek medewerker
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000108', 'B1', 'schrijven', 'Motivatiebrief voor logistiek medewerker',
  'Een distributiecentrum zoekt een logistiek medewerker die nauwkeurig werkt, fysiek werk aankan en in wisselende diensten beschikbaar is. Je hebt twee jaar magazijnervaring.', 118, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000108', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Een distributiecentrum zoekt een logistiek medewerker die nauwkeurig werkt, fysiek werk aankan en in wisselende diensten beschikbaar is. Je hebt twee jaar magazijnervaring. Schrijf 150-200 woorden. Verbind je ervaring aan de vacature, geef een voorbeeld en noem je beschikbaarheid.","minWords":150,"modelAnswer":"Geachte heer/mevrouw,\n\nMet belangstelling solliciteer ik naar de functie van logistiek medewerker. De afgelopen twee jaar heb ik in een magazijn voor huishoudelijke artikelen gewerkt. Daar was ik verantwoordelijk voor het verzamelen, controleren en verzendklaar maken van bestellingen.\n\nNauwkeurig werken vind ik belangrijk. In mijn huidige team controleer ik bijvoorbeeld altijd artikelnummer en hoeveelheid voordat een doos wordt gesloten. Daardoor heb ik het afgelopen halfjaar nauwelijks correcties op mijn orders gehad. Ik ben gewend om veel te lopen en dozen veilig te tillen. Ook heb ik een interne instructie gevolgd over het gebruik van een elektrische palletwagen.\n\nWisselende diensten zijn voor mij mogelijk. Ik ben doordeweeks zowel vroeg als in de avond beschikbaar en kan twee zaterdagen per maand werken. Collega''s omschrijven mij als rustig, betrouwbaar en behulpzaam.\n\nGraag licht ik mijn motivatie in een gesprek verder toe.\n\nMet vriendelijke groet,\nAndrei Popescu"}'::jsonb, null, 1
);

-- SCH-19 (B1) — Ingezonden brief over tijdelijke parksluiting
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000109', 'B1', 'schrijven', 'Ingezonden brief over tijdelijke parksluiting',
  'De gemeente wil een buurtpark drie maanden volledig sluiten voor renovatie. Jij steunt de renovatie, maar wilt dat een deel toegankelijk blijft.', 119, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000109', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De gemeente wil een buurtpark drie maanden volledig sluiten voor renovatie. Jij steunt de renovatie, maar wilt dat een deel toegankelijk blijft. Schrijf 150-200 woorden met standpunt, twee argumenten, begrip voor de gemeente en een alternatief.","minWords":150,"modelAnswer":"Geachte redactie,\n\nDe geplande renovatie van het Westerpark is volgens mij nodig. De speeltoestellen zijn verouderd en na regen blijven paden lang modderig. Toch vind ik een volledige sluiting van drie maanden te ingrijpend.\n\nTen eerste is het park de enige groene ontmoetingsplek in onze dichtbebouwde wijk. Vooral ouderen en gezinnen zonder tuin gebruiken het dagelijks. Ten tweede zullen kinderen bij een volledige sluiting waarschijnlijk uitwijken naar drukke straten en parkeerplaatsen, wat minder veilig is. Ik begrijp dat aannemers ruimte nodig hebben en dat bezoekers niet door een bouwterrein mogen lopen.\n\nDaarom stel ik voor de werkzaamheden in fasen uit te voeren. Eerst kan de noordkant worden aangepakt terwijl het zuidelijke grasveld via een veilige ingang openblijft. Daarna kunnen de delen worden omgewisseld. Dit duurt mogelijk iets langer, maar de buurt behoudt ten minste een beperkte buitenruimte.\n\nMet vriendelijke groet,\nEen bewoner van de wijk"}'::jsonb, null, 1
);

-- SCH-20 (B1) — Incidentrapport op het werk
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000110', 'B1', 'schrijven', 'Incidentrapport op het werk',
  'In een magazijn gleed een collega uit over water naast een defecte koelkast. Er was geen ernstig letsel. Jij zag het gebeuren.', 120, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000110', 'writing_task', 'Schrijf de tekst.', '{"instructions":"In een magazijn gleed een collega uit over water naast een defecte koelkast. Er was geen ernstig letsel. Jij zag het gebeuren. Schrijf 140-190 woorden. Vermeld datum/tijd, locatie, feitelijke gebeurtenis, directe acties en aanbevolen vervolg. Vermijd schuld zonder bewijs.","minWords":140,"modelAnswer":"**Incidentrapport**\n**Datum en tijd:** 12 november, circa 10.20 uur\n**Locatie:** personeelskeuken, begane grond\n\nOmstreeks 10.20 uur liep collega D. Jansen de personeelskeuken binnen. Naast de koelkast lag een plas water van ongeveer één meter breed. De collega gleed uit en kwam op de linkerknie terecht. Ik heb niet gezien wanneer het water is ontstaan. De koelkast maakte op dat moment een ongewoon hard geluid en onder het apparaat was vocht zichtbaar.\n\nIk heb de collega geholpen op een stoel te gaan zitten en de bedrijfshulpverlener gebeld. Die controleerde de knie; medische spoedzorg was niet nodig. Vervolgens hebben we de keuken tijdelijk afgesloten en de stekker van de koelkast laten verwijderen door de facilitaire medewerker. De vloer is gedroogd en er is een waarschuwingsbord geplaatst.\n\nAanbevolen wordt de koelkast technisch te laten onderzoeken en in het team opnieuw af te spreken dat lekkages onmiddellijk worden afgezet en gemeld."}'::jsonb, null, 1
);

-- SCH-21 (B1) — E-mail aan een docent over voortgang
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000111', 'B1', 'schrijven', 'E-mail aan een docent over voortgang',
  'Je volgt een B1-cursus. Lezen gaat goed, maar luisteren en spreken blijven achter. Je wilt gericht advies en extra oefening.', 121, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000111', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je volgt een B1-cursus. Lezen gaat goed, maar luisteren en spreken blijven achter. Je wilt gericht advies en extra oefening. Schrijf 140-190 woorden. Beschrijf je voortgang, geef voorbeelden, formuleer twee vragen en stel een eigen actie voor.","minWords":140,"modelAnswer":"Beste mevrouw Smit,\n\nIk wil graag mijn voortgang in de B1-cursus met u bespreken. Bij lezen merk ik duidelijke verbetering: ik begrijp de hoofdgedachte van nieuwsberichten en kan meestal de juiste details vinden. Bij luisteren mis ik echter informatie wanneer mensen snel spreken of wanneer meerdere personen door elkaar praten. Tijdens gesprekken weet ik vaak wel wat ik wil zeggen, maar ik zoek te lang naar woorden en gebruik daardoor korte zinnen.\n\nKunt u adviseren welke luisteroefeningen het best bij dit probleem passen? Daarnaast hoor ik graag of ik tijdens de les vaker een korte presentatie of rollenspel kan doen. Zelf wil ik drie keer per week tien minuten naar een nieuwsfragment luisteren en daarna mondeling de kern samenvatten.\n\nZou u volgende week kort met mij kunnen bekijken of dit plan realistisch is en hoe ik mijn vooruitgang kan meten?\n\nMet vriendelijke groet,\nHana Saleh"}'::jsonb, null, 1
);

-- SCH-22 (B1) — Voorstel voor een buurtactiviteit
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000112', 'B1', 'schrijven', 'Voorstel voor een buurtactiviteit',
  'Je wilt elke maand een gezamenlijke kookavond organiseren voor nieuwe en bestaande bewoners.', 122, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000112', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Je wilt elke maand een gezamenlijke kookavond organiseren voor nieuwe en bestaande bewoners. Schrijf 160-210 woorden. Beschrijf doel, doelgroep, uitvoering, kosten/middelen, risico en eerste test.","minWords":160,"modelAnswer":"**Voorstel: maandelijkse kookavond `Samen aan tafel`**\n\nHet doel van de kookavond is dat nieuwe en bestaande buurtbewoners elkaar op een informele manier leren kennen. De activiteit is bedoeld voor volwassenen en gezinnen uit de wijk; kinderen kunnen onder begeleiding meedoen.\n\nIedere maand koken deelnemers in kleine groepen drie eenvoudige gerechten uit verschillende landen. Het buurtcentrum stelt de keuken en tafels beschikbaar. Deelnemers betalen vijf euro per volwassene; voor kinderen is deelname gratis. Met dit bedrag worden basisingrediënten gekocht. We vragen twee vrijwilligers voor de inschrijving en de veiligheid in de keuken.\n\nEen mogelijk risico is dat er te veel of juist te weinig deelnemers komen. Daarom werken we met vooraf aanmelden en een maximum van dertig personen. Ook vragen we bij inschrijving naar allergieën.\n\nIk stel voor eerst één proefavond op vrijdag 20 september te organiseren. Na afloop verzamelen we korte reacties over sfeer, kosten en organisatie. Bij voldoende belangstelling kan de activiteit daarna maandelijks doorgaan."}'::jsonb, null, 1
);

-- SCH-23 (B1) — Een informatieve tekst samenvatten
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000113', 'B1', 'schrijven', 'Een informatieve tekst samenvatten',
  null, 123, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000113', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf een neutrale samenvatting van 90-120 woorden. Neem doel, werkwijze, duur/evaluatie en verschillende reacties op. Voeg geen eigen mening toe.","minWords":90,"modelAnswer":"Een bibliotheek gaat zes maanden lang testen of leden naast boeken ook gereedschap kunnen lenen. Het doel is te voorkomen dat inwoners apparaten aanschaffen die zij nauwelijks gebruiken. In het begin bestaat de collectie onder andere uit boormachines, naaimachines en tuingereedschap. Bij bepaalde apparaten moeten gebruikers eerst een veiligheidsinstructie volgen. Na afloop beoordeelt de bibliotheek hoe vaak de materialen zijn geleend, hoeveel schade en kosten er waren en wat gebruikers van de dienst vinden. De reacties zijn verdeeld: sommige inwoners waarderen het initiatief, terwijl anderen vinden dat het uitlenen van gereedschap niet bij de kerntaak van een bibliotheek hoort."}'::jsonb, null, 1
);

-- SCH-24 (B2) — Betoog over structureel thuiswerken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000114', 'B2', 'schrijven', 'Betoog over structureel thuiswerken',
  null, 124, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000114', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Schrijf 230-300 woorden. Formuleer een genuanceerd standpunt, bespreek minstens twee voordelen en twee bezwaren, reageer op een tegenargument en sluit af met voorwaarden.","minWords":230,"modelAnswer":"**Thuiswerken als uitgangspunt, niet als absoluut recht**\n\nKantoormedewerkers zouden in beginsel twee dagen per week thuis moeten kunnen werken, maar alleen binnen duidelijke afspraken over functie, samenwerking en bereikbaarheid. Een dergelijk uitgangspunt geeft werknemers voorspelbaarheid zonder te doen alsof iedere taak op afstand uitvoerbaar is.\n\nThuiswerken kan reistijd verminderen en medewerkers meer concentratie bieden voor taken die weinig overleg vragen. Daarnaast kan een ruimere keuze bijdragen aan werk-privébalans en het aantrekkelijker maken om mensen uit een groter gebied aan te nemen. Daar staan reële bezwaren tegenover. Nieuwe collega''s leren minder vanzelfsprekend van informele contacten, teams kunnen versnipperen en niet iedereen beschikt thuis over een rustige of ergonomische werkplek. Ook zijn er functies waarin fysieke aanwezigheid noodzakelijk is.\n\nWerkgevers voeren vaak aan dat een wettelijk of organisatorisch recht hun flexibiliteit beperkt. Dat bezwaar is deels terecht, maar een algemene afwijzing geeft de werkgever juist te veel ruimte om zonder concrete onderbouwing vast te houden aan oude gewoonten. Een betere benadering is dat een weigering gekoppeld moet zijn aan aantoonbare eisen van de functie of ernstige gevolgen voor het team.\n\nVoor succesvolle invoering zijn vaste gezamenlijke kantoordagen, meetbare resultaatafspraken, goede digitale toegang en periodieke evaluatie nodig. Bovendien moet de werkgever een werkplek op kantoor beschikbaar houden. Zo wordt thuiswerken geen individueel privilege, maar een verantwoord onderdeel van de werkorganisatie."}'::jsonb, null, 1
);

-- SCH-25 (B2) — Beleidsmemo over openingstijden van de bibliotheek
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000115', 'B2', 'schrijven', 'Beleidsmemo over openingstijden van de bibliotheek',
  'De bibliotheek wil met hetzelfde personeelsbudget beter bereikbaar zijn. Uit gegevens blijkt: weinig bezoekers maandagochtend, veel vraag woensdagavond, studenten vragen om zondagse studieplekken, en vrijwilligers mogen geen taken uitvoeren waarvoor privacygevoelige persoonsgegevens nodig zijn.', 125, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000115', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De bibliotheek wil met hetzelfde personeelsbudget beter bereikbaar zijn. Uit gegevens blijkt: weinig bezoekers maandagochtend, veel vraag woensdagavond, studenten vragen om zondagse studieplekken, en vrijwilligers mogen geen taken uitvoeren waarvoor privacygevoelige persoonsgegevens nodig zijn. Schrijf 230-300 woorden aan de directie met probleemanalyse, aanbevolen rooster, randvoorwaarden, risico''s en evaluatie.","minWords":230,"modelAnswer":"**Aan:** Directie Bibliotheek Centrum\n**Onderwerp:** proef met aangepaste openingstijden\n\n**Aanleiding**\nDe huidige openingstijden sluiten onvoldoende aan op het feitelijke gebruik. Maandagochtend is het structureel rustig, terwijl de woensdagavond druk is en studenten herhaaldelijk vragen om studieplekken op zondag. Binnen het bestaande personeelsbudget is uitbreiding alleen mogelijk door uren te verschuiven.\n\n**Advies**\nIk adviseer een proef van vier maanden waarbij de vestiging op maandag twee uur later opent, op woensdag tot 21.00 uur openblijft en op zondag van 12.00 tot 17.00 uur uitsluitend als studie- en afhaallocatie functioneert. Op zondag kunnen getrainde vrijwilligers bezoekers ontvangen en toezicht houden. Handelingen met persoonsgegevens, zoals nieuwe lidmaatschappen, boetes of inzage in accounts, blijven voorbehouden aan een aanwezige medewerker. Daarom is minimaal één beroepskracht noodzakelijk.\n\n**Randvoorwaarden en risico''s**\nHet rooster moet voldoen aan rusttijden en medewerkers moeten tijdig instemmen met structurele avond- of weekenddiensten. Een risico is dat de zondagse belangstelling lager uitvalt dan verwacht. Ook kan een beperkte dienstverlening tot onduidelijkheid leiden. Heldere communicatie bij de ingang en online is daarom essentieel.\n\n**Evaluatie**\nMeet per tijdsblok bezoekersaantallen, personeelskosten, wachttijd, incidenten en tevredenheid. Na vier maanden kan de directie besluiten de proef voort te zetten, aan te passen of te beëindigen."}'::jsonb, null, 1
);

-- SCH-26 (B2) — Formele reactie op een klacht
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000116', 'B2', 'schrijven', 'Formele reactie op een klacht',
  'Een klant klaagt dat een cursus twee keer op het laatste moment is afgezegd. De organisatie erkent de slechte communicatie. Eén afzegging kwam door ziekte, de andere door een fout in de planning. Je biedt keuze uit geld terug of een nieuwe cursus plus extra individuele sessie.', 126, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000116', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Een klant klaagt dat een cursus twee keer op het laatste moment is afgezegd. De organisatie erkent de slechte communicatie. Eén afzegging kwam door ziekte, de andere door een fout in de planning. Je biedt keuze uit geld terug of een nieuwe cursus plus extra individuele sessie. Schrijf 220-280 woorden. Erken ervaring en fout, leg beknopt uit zonder defensief te worden, bied concrete opties en voorkom herhaling.","minWords":220,"modelAnswer":"**Onderwerp: reactie op uw klacht over cursusannuleringen**\n\nGeachte mevrouw De Boer,\n\nDank dat u ons heeft laten weten hoe u de twee annuleringen hebt ervaren. U mocht verwachten dat de cursus volgens planning zou doorgaan en dat een wijziging tijdig en duidelijk werd gecommuniceerd. Dat is niet gebeurd. Wij begrijpen dat dit extra vervelend is omdat u beide keren opvang en reistijd had geregeld.\n\nDe eerste bijeenkomst moest door onverwachte ziekte van de docent worden geannuleerd. Bij de tweede annulering is intern een planningsfout gemaakt. Die omstandigheden verklaren wat er is gebeurd, maar nemen niet weg dat onze communicatie te laat was en dat wij onvoldoende naar een alternatief hebben gezocht. Daarvoor bieden wij onze excuses aan.\n\nWij bieden u graag de keuze uit twee oplossingen. U kunt het volledige cursusbedrag binnen tien werkdagen terugontvangen. U kunt ook kosteloos deelnemen aan de nieuwe cursus die op 14 september start; daarbij krijgt u één individuele sessie van zestig minuten aangeboden. Laat u ons vóór 1 september weten welke optie uw voorkeur heeft?\n\nOm herhaling te voorkomen, is voortaan een tweede medewerker verantwoordelijk voor de controle van docent- en lokaalplanning. Daarnaast informeren wij deelnemers bij een wijziging zowel per e-mail als per sms.\n\nMet vriendelijke groet,\nTeamleider Opleidingen"}'::jsonb, null, 1
);

-- SCH-27 (B2) — Reflectieverslag van een stage
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000117', 'B2', 'schrijven', 'Reflectieverslag van een stage',
  'Tijdens je stage leidde je voor het eerst een teamoverleg. Je agenda was duidelijk, maar je liet één dominante deelnemer te lang spreken en sloot af zonder taken samen te vatten.', 127, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000117', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Tijdens je stage leidde je voor het eerst een teamoverleg. Je agenda was duidelijk, maar je liet één dominante deelnemer te lang spreken en sloot af zonder taken samen te vatten. Schrijf 230-300 woorden volgens de lijn situatie-handelen-effect-leerpunt-volgende actie. Vermijd alleen algemene uitspraken.","minWords":230,"modelAnswer":"**Reflectie op het leiden van een teamoverleg**\n\nTijdens mijn stage heb ik voor het eerst het wekelijkse teamoverleg geleid. Mijn doel was binnen veertig minuten drie knelpunten te bespreken en per punt een besluit te nemen. Vooraf stuurde ik een agenda met tijdsblokken, waardoor de deelnemers voorbereid waren en het overleg op tijd begon.\n\nBij het tweede onderwerp nam één deelnemer echter langdurig het woord. Ik stelde wel een inhoudelijke vraag, maar greep niet in toen het antwoord steeds verder van het besluit af kwam te staan. Daardoor bleef voor het laatste agendapunt weinig tijd over. Aan het einde benoemde ik de genomen besluiten, maar ik vergat per actie een eigenaar en deadline te bevestigen. De volgende dag bleek dat twee collega''s dachten dat iemand anders verantwoordelijk was.\n\nMijn sterke punt was de voorbereiding: de agenda gaf richting en de relevante documenten waren beschikbaar. Mijn belangrijkste leerpunt is dat voorzitten ook betekent dat ik spreektijd begrens en expliciet controleer wie wat doet. Ik vond ingrijpen onbeleefd, maar zie nu dat een respectvolle onderbreking juist de gezamenlijke tijd beschermt.\n\nBij het volgende overleg kondig ik vooraf aan dat ik bijdragen kan samenvatten of onderbreken. Ik gebruik per agendapunt een zichtbaar besluitblok met actie, verantwoordelijke en datum. Na afloop stuur ik binnen een uur een korte actielijst en vraag ik deelnemers onduidelijkheden dezelfde dag te melden."}'::jsonb, null, 1
);

-- SCH-28 (B2) — Twee mobiliteitsvoorstellen vergelijken
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000118', 'B2', 'schrijven', 'Twee mobiliteitsvoorstellen vergelijken',
  'Een organisatie wil woon-werkverkeer verduurzamen.', 128, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000118', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Een organisatie wil woon-werkverkeer verduurzamen. Schrijf 230-300 woorden. Vergelijk effectiviteit, eerlijkheid, uitvoerbaarheid en uitzonderingen. Geef een gemotiveerde aanbeveling.","minWords":230,"modelAnswer":"**Advies duurzame reiskostenregeling**\n\nVoorstel A is administratief aantrekkelijk: iedere werknemer ontvangt volgens een eenvoudige regel een hogere vergoeding. Het nadeel is dat de organisatie daarmee vooral extra geld uitgeeft zonder een duidelijke prikkel om anders te reizen. Een medewerker die al fietst en een medewerker die dagelijks alleen in de auto rijdt, worden in wezen hetzelfde behandeld.\n\nVoorstel B sluit beter aan bij het duurzaamheidsdoel. Volledige vergoeding van openbaar vervoer en een fietsvergoeding verlagen de financiële drempel voor alternatieven. De lagere autovergoeding maakt bovendien zichtbaar dat niet ieder vervoermiddel dezelfde maatschappelijke kosten heeft. Deze regeling vraagt echter meer registratie en kan onredelijk uitpakken voor medewerkers met nachtdiensten, een beperking of een werklocatie zonder bruikbare ov-verbinding.\n\nIk adviseer daarom voorstel B in aangepaste vorm. De organisatie kan declaraties grotendeels automatiseren via een mobiliteitskaart en een app voor fietskilometers. Voor medewerkers die aantoonbaar geen redelijk alternatief hebben, blijft de huidige autovergoeding gelden. Ook is een overgangsperiode van zes maanden wenselijk, zodat werknemers hun reispatroon kunnen aanpassen.\n\nNa één jaar moeten CO2-uitstoot, gebruik per vervoermiddel, kosten en ervaringen van verschillende personeelsgroepen worden geëvalueerd. Zo combineert de regeling een gerichte duurzaamheidsprikkel met uitvoerbare en uitlegbare uitzonderingen."}'::jsonb, null, 1
);

-- SCH-29 (B2) — Artikel over verduurzaming in de wijk
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000119', 'B2', 'schrijven', 'Artikel over verduurzaming in de wijk',
  'De wijk wil energie besparen. Huurders vrezen huurverhoging, woningeigenaren zien op tegen investeringen en de gemeente biedt energiescans en een collectieve inkoopactie.', 129, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000119', 'writing_task', 'Schrijf de tekst.', '{"instructions":"De wijk wil energie besparen. Huurders vrezen huurverhoging, woningeigenaren zien op tegen investeringen en de gemeente biedt energiescans en een collectieve inkoopactie. Schrijf 250-320 woorden voor de wijknieuwsbrief. Leg belangen uit, geef praktische routes voor verschillende bewoners en vermijd simplistische beloftes.","minWords":250,"modelAnswer":"**Een zuinigere wijk vraagt om verschillende routes**\n\nVeel bewoners willen een lagere energierekening en een comfortabeler huis, maar niet iedereen kan dezelfde maatregelen nemen. Een eigenaar kan zelf besluiten over isolatie of zonnepanelen, terwijl een huurder afhankelijk is van de verhuurder. Bovendien zijn grote investeringen niet voor ieder huishouden betaalbaar, ook niet wanneer ze zich op lange termijn terugverdienen.\n\nDe gemeente start daarom gratis energiescans. Een adviseur bekijkt waar warmte verloren gaat en maakt onderscheid tussen kleine ingrepen, zoals tochtstrips en radiatorfolie, en grotere maatregelen, zoals dak- of glasisolatie. Voor woningeigenaren volgt een gezamenlijke inkoopactie. Die kan de prijs verlagen, maar bewoners moeten nog steeds offertes vergelijken, financiering beoordelen en controleren welke garanties gelden.\n\nHuurders kunnen gebreken en hoge stookkosten gezamenlijk bij de verhuurder aankaarten. Het is belangrijk dat vooraf duidelijk is welke werkzaamheden worden uitgevoerd, of daar een huurwijziging tegenover staat en hoe bewoners bij de planning worden betrokken. Een bewonersgroep kan helpen om vragen te bundelen, maar kan geen individuele juridische uitkomst beloven.\n\nNiet iedere maatregel is in ieder huis zinvol. Begin daarom met inzicht in verbruik en bouwkundige staat. De eerste informatieavond is op 9 oktober in het buurthuis. Bewoners kunnen zich daar aanmelden voor een scan of voor de werkgroep huurwoningen. Zo werken we stap voor stap aan besparing, zonder verschillen tussen huishoudens te negeren."}'::jsonb, null, 1
);

-- SCH-30 (B2) — Managementsamenvatting over AI-roosterplanning
insert into lessons (id, level_code, skill_code, title, description, sort_order, is_free) values (
  'b0000000-0000-4000-8000-000000000120', 'B2', 'schrijven', 'Managementsamenvatting over AI-roosterplanning',
  'Een zorgorganisatie test software die automatisch personeelsroosters maakt. De proef leverde 30% minder plantijd op en iets minder open diensten. Medewerkers klaagden over onvoorspelbare wisselingen en de software hield onvoldoende rekening met informele afspraken. Handmatige correcties waren mogelijk, maar redenen werden niet vastgelegd.', 130, false
);
insert into exercises (lesson_id, type, prompt, content, correct_answer, sort_order) values (
  'b0000000-0000-4000-8000-000000000120', 'writing_task', 'Schrijf de tekst.', '{"instructions":"Een zorgorganisatie test software die automatisch personeelsroosters maakt. De proef leverde 30% minder plantijd op en iets minder open diensten. Medewerkers klaagden over onvoorspelbare wisselingen en de software hield onvoldoende rekening met informele afspraken. Handmatige correcties waren mogelijk, maar redenen werden niet vastgelegd. Schrijf 230-300 woorden. Vat resultaten samen, analyseer risico''s, geef voorwaarden voor voortzetting en formuleer een besluitadvies.","minWords":230,"modelAnswer":"**Managementsamenvatting: proef AI-ondersteunde roosterplanning**\n\nDe proef met automatische roosterplanning heeft aantoonbare operationele voordelen opgeleverd. De planners besteedden ongeveer dertig procent minder tijd aan het eerste conceptrooster en het aantal openstaande diensten nam licht af. De software lijkt daarmee geschikt om een arbeidsintensieve basistaak te ondersteunen.\n\nDe proef laat echter ook zien dat efficiëntie niet gelijkstaat aan roosterkwaliteit. Medewerkers ervoeren meer onverwachte wisselingen en informele, maar relevante afspraken—bijvoorbeeld vaste zorgtaken of combinaties die binnen een team niet werkbaar zijn—werden niet consequent meegenomen. Handmatige correcties konden dit herstellen, maar omdat de reden voor aanpassingen niet werd geregistreerd, leert de organisatie onvoldoende welke regels structureel ontbreken. Bovendien is niet duidelijk of bepaalde groepen vaker ongunstige diensten kregen.\n\nIk adviseer de software niet direct organisatiebreed in te voeren, maar de proef met drie maanden te verlengen. Voorwaarde is dat harde en zachte roosterbeperkingen transparant worden vastgelegd, iedere handmatige correctie een reden krijgt en uitkomsten per personeelsgroep worden gecontroleerd. Medewerkers moeten vóór publicatie een korte reactietermijn krijgen, terwijl een planner eindverantwoordelijk blijft.\n\nDe vervolgmeting moet naast plantijd en open diensten ook voorspelbaarheid, aantal correcties, ervaren eerlijkheid en ziekteverzuim omvatten. Bij verbetering op efficiëntie én medewerkerservaring kan gefaseerde invoering volgen. Blijven de wisselingen onvoorspelbaar of ontstaan systematische nadelen, dan moet de organisatie het systeem aanpassen of beëindigen."}'::jsonb, null, 1
);
